window.__QUIZ_DATA__=[{"id":"objective>Geography>2014>1","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The scale of the map is statement from one centimetre on the map represents","images":["data:image/png;base64,"],"options":{"A":"four kilometres on the ground","B":"three kilometres on the ground","C":"one kilometres on the ground","D":"half kilometres on the ground"},"answer":"C","explanation":"The scale of the map, 1:100,000 in statement form is 1cm on the map represents 1km on the ground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>2","subject":"Geography","year":"2014","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"What is the distance by rail from Ore to Kambi?","images":[],"options":{"A":"18.0 km","B":"13.5 km","C":"10.0 km","D":"4.5 km"},"answer":"C","explanation":"The scale of the map in statement form is one centimeters on the map represents one kilometer on the ground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>3","subject":"Geography","year":"2014","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : COMMUNICATION","question":"Which of the following towns is visible from ore?","images":[],"options":{"A":"Isapa","B":"Isholo","C":"Kambi","D":"Aye"},"answer":"D","explanation":"Aye is visible from Ore. Other options are not visible from Ore","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>4","subject":"Geography","year":"2014","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"The lower banks of River Ati could best be used for the cultivation of","images":[],"options":{"A":"coco yam","B":"wheat","C":"rice","D":"yam"},"answer":"C","explanation":"The lower bank of River Ati could best be used for the cultivation of rice; this part of River Ati is liable to flooding","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>5","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The growth of IGBOLA settlement is as a result of its location as the","images":[],"options":{"A":"most central position on the map","B":"largest undulating terrain available for agricultural activities","C":"most apparently secured place in time of war","D":"meeting point of different route ways"},"answer":"D","explanation":"The growth of IGBONLA settlement is as a result of its location as the meeting point of different route ways.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>6","subject":"Geography","year":"2014","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Plantation agriculture is practiced in the","images":[],"options":{"A":"northern","B":"northwest","C":"southeast","D":"southwest"},"answer":"B","explanation":"The key for plantation agriculture mostly dominates the region of the map","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>7","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The angular bearing of Faki from IGBONLA is approximately","images":[],"options":{"A":"105o","B":"230o","C":"310o","D":"355o"},"answer":"C","explanation":"Using a protractor, the angular bearing of Faki from IGBONLA is 310o (N50oW)","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>8","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the contour interval on the map?","images":[],"options":{"A":"500 m","B":"300 m","C":"250 m","D":"100 m"},"answer":"D","explanation":"The contour interval is 100m. If we consider the in all the settlement","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>9","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The highest point on the map is","images":[],"options":{"A":"350 m","B":"450 m","C":"850 m","D":"950 m"},"answer":"C","explanation":"The highest point on the map is 850m located around Kanbi","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>10","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The likely reason for the construction of railway to link Ore with Kanbi is to","images":[],"options":{"A":"provide for the inadequacies in road the connections","B":"provides means of distributing manufactured goods from Kambi","C":"convey mineral products from ore inland","D":"convey a large population of people out of Ore"},"answer":"C","explanation":"If you study the map very well, Ore is a mining area and there is no major road linking Ore to Kamb. Hence, there is a need for a rail network so that mineral product will be conveyed from Ore inland.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>11","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The nearest planet to the sun is the","images":[],"options":{"A":"Pluto","B":"Earth","C":"Mars","D":"Mercury"},"answer":"D","explanation":"The nearest planet to the sun is mercury.      M1 \u21d2 Mercury M2 \u21d2 Mars U \u21d2 Uranus   V \u21d2  Venus J \u21d2  Jupiter N \u21d2  Neptune   E \u21d2  Earth  S \u21d2  Saturn P \u21d2  Pluto","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>12","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The Longitude that joins Longitude 180o at the opposite side of the globe to form a Great Circle is","images":[],"options":{"A":"Longitude 0o","B":"Longitude 30oE","C":"Longitude 150o W","D":"Longitude 170oW"},"answer":"A","explanation":"The longitude that joins Longitude 180o at the opposite side of the globe to form a great circle is longitude 0o","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>13","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following lines of latitudes divides the earth into two hemispheres?","images":[],"options":{"A":"Tropical Cancer","B":"Tropic of Capricorn","C":"The Equator","D":"Antartic Circle"},"answer":"C","explanation":"The equator divides the Earth into two hemisphere","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>14","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The part of the earth's crust that is covered by ocean and seas is called","images":[],"options":{"A":"biosphere","B":"ionosphere","C":"stratosphere","D":"hydrosphere"},"answer":"D","explanation":"The part of the earth's crust that is covered by ocean and seas is called the hydrosphere. The hydrosphere includes all the waters on the earth's surface, such as lakes and seas, and sometimes includes water over the earth's surface, such as clouds. The other options, biosphere, ionosphere, and stratosphere, refer to other parts of the earth's system.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>15","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The angular distance of a point on the Earth's surface measured in degree from the centre of the Earth east or west of the Greenwich Meridian is known as","images":[],"options":{"A":"axis","B":"latitude","C":"orbit","D":"longitude"},"answer":"D","explanation":"The angular distance of a point on the Earth's surface measured in degree from the centre of the Earth east or west of the Greenwich Meridian is known as the longitude","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>16","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"An example of an organically formed sedimentary rock is","images":[],"options":{"A":"rock salt","B":"granite","C":"sandstone","D":"coal"},"answer":"D","explanation":"Coal is an organically formed sedimentary rock.   \u21d2 Coal is a black rock formed from prehistoric plant remains, composed largely of carbon and burned as fuel.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>17","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Sills, dykes and batholiths are examples of","images":[],"options":{"A":"intrusive volcanic landforms","B":"extrusive volcanic landforms","C":"landforms from earthquakes","D":"depositional landforms"},"answer":"A","explanation":"Sills, dykes and batholiths are example of intrusive volcanic land forms  \u21d2 Sills: A horizontal layer of igneous rock between older rock beds   \u21d2 Dykes: It is a body of rock (usually igneous) originally filling a fissure but now of ten rising above the older stratum as it is eroded away.   \u21d2 Batholith: A large irregular mass of intrusive igneous rock that has melted or forced itself into surrounding strata.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>18","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"In which part of the atmosphere does rain clouds develop?","images":[],"options":{"A":"Troposphere","B":"Stratosphere","C":"Thermosphere","D":"Exosphere"},"answer":"A","explanation":"The part of atmosphere where rain cloud is formed is called TROPOSPHERE.   \u21d2 Troposphere: The lower level of the atmosphere extending from the surface of the Earth or another celestial body up to the tropopause. It is characterized by connective air movements and a large vertical temperature change.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>19","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The process of headward erosion will lead to the formation of","images":[],"options":{"A":"alluvial cones","B":"pot holes","C":"river capture","D":"oxbow lakes"},"answer":"D","explanation":"The process of headward erosion will lead to the formation of river capture","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>20","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which type of rock are quartzite schist and marble?","images":[],"options":{"A":"Metamorphic","B":"Igneous","C":"Sedimentary","D":"Volcanic"},"answer":"A","explanation":"Quartzite, schist, and marble are all examples of metamorphic rocks. Metamorphic rocks are formed from the transformation of existing rock types, in a process called metamorphism, which means 'change in form'. The original rock (protolith) is subjected to heat and pressure, causing profound physical or chemical change. Therefore, the correct answer is 'Metamorphic'.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>21","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"A plateau that is enclosed by two fold mountains is called","images":[],"options":{"A":"an intermont plateau","B":"a lava plateau","C":"a volcanic plateau","D":"a dissected plateau"},"answer":"A","explanation":"An intermont plateau is a plateau that is enclosed by two fold mountains. Fold mountains are formed when two tectonic plates collide, causing the crust to buckle and fold. The area between these folds can form a plateau. Therefore, the correct answer is 'an intermont plateau'.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>22","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The nearest part of the ocean basin to the continent is called","images":[],"options":{"A":"deep sea plain","B":"continental slope","C":"continental shelf","D":"abyssal plain"},"answer":"A","explanation":"The continental shelf is the nearest part of the ocean basin to the bedding plane.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>23","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The feature formed by cooling of molten magma across the bedding plane is","images":[],"options":{"A":"sill","B":"dyke","C":"batholith","D":"Laccolith"},"answer":"C","explanation":"Sill is the feature formed by cooling of molten magma across the bedding plane.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>24","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Lines on maps joining places of same temperature above sea level are called","images":[],"options":{"A":"isotherms","B":"isohyets","C":"isobars","D":"isohalines"},"answer":"A","explanation":"Lines on maps joining places of the same temperature above sea level are called isotherms. An isotherm is a line on a map or diagram of a particular type (such as a weather map) connecting points having the same temperature at a given time or the same mean temperature for a given period.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>25","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"When wet and dry bulb thermometers record the same temperature, it means","images":[],"options":{"A":"air is dry","B":"air is saturated","C":"humidity is high","D":"humidity is low"},"answer":"B","explanation":"When the wet and dry bulb thermometers record the same temperature, it means that the air is saturated. This is because the wet bulb thermometer cools due to evaporation, and if there is no temperature difference between the wet and dry bulb, it means no evaporation is taking place, hence the air is saturated.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>26","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following best describes the harmattan? It is","images":[],"options":{"A":"wet and cold","B":"dry, cold and wet","C":"dry and dusty","D":"of high relative humidity"},"answer":"C","explanation":"The harmattan period is a dry and dusty wind which blows from the Sahara over the Atlntic coast of West Africa in December, January and February, being a hot wind in some areas and a cold wind in others.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>27","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"A disaster caused by nature or man which poses a serious danger to lives and properties of the people is called environmental","images":[],"options":{"A":"intervention","B":"hazard","C":"interaction","D":"change"},"answer":"B","explanation":"Environmental hazard is a disaster caused by nature or man which poses serious danger to lives and properties of the people.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>28","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Environmental balance includes all the following except","images":[],"options":{"A":"hydrological circle","B":"carbon cycle","C":"food chain and food web","D":"earthquake cycle"},"answer":"D","explanation":"Environmental balance refers to the state of equilibrium within the environment, which is maintained by the interactions of organisms and their surroundings. It includes elements like the hydrological cycle (water cycle), carbon cycle, and food chains and webs, which are all biological and physical processes. The earthquake cycle, on the other hand, is a geophysical process that does not directly contribute to the environmental balance. It is more related to the tectonic activities of the Earth.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>29","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Coal and mineral oil are usually found embedded in","images":[],"options":{"A":"crystalline rocks","B":"igneous rocks","C":"metamorphic rocks","D":"sedimentary rocks"},"answer":"D","explanation":"Coal and mineral oil are organic resources that are formed from the remains of plants and animals. These remains get buried under layers of sediment and over millions of years, due to heat and pressure, they transform into coal and mineral oil. This process of formation occurs in sedimentary rocks, which are formed from the accumulation of sediments. Therefore, coal and mineral oil are usually found embedded in sedimentary rocks.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>30","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The Alps, Himalayas and Rocky mountains are","images":[],"options":{"A":"extinct volcanoes","B":"fold mountains","C":"residual mountains","D":"block mountains"},"answer":"B","explanation":"The Alps, Himalayas, and Rocky mountains are examples of fold mountains. Fold mountains are formed when two tectonic plates collide and the edges of these plates fold up to form mountains. This is a result of the Earth's crust being compressed. Extinct volcanoes, residual mountains, and block mountains are different types of mountains formed through different geological processes.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>31","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following landforms is associated with wind deposition?","images":[],"options":{"A":"Barchan","B":"Rock pedestal","C":"Yardang","D":"Zeugen"},"answer":"A","explanation":"Barchan is an arc-shaped sand ridge comprised of well-sorted sand. It is associated with wind deposition.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>32","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Swallow holes and disappearing streams are usually associated with","images":[],"options":{"A":"limestone regions","B":"humid regions","C":"upper course of rivers","D":"desert regions"},"answer":"A","explanation":"Swallow holes and disappearing streams are usually associated with limestone regions. This is because limestone is a soluble rock and can be eroded by water to form features like swallow holes (also known as sinkholes) and disappearing streams.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>33","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following is a fossil fuel?","images":[],"options":{"A":"Lignite","B":"Mica","C":"Granite","D":"Gnesis"},"answer":"A","explanation":"Lignite is a type of coal and is considered a fossil fuel. Fossil fuels are fuels formed by natural processes such as anaerobic decomposition of buried dead organisms. The other options, Mica, Granite, and Gnesis, are types of rocks and not fossil fuels.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>34","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"The major source of power for most terrestrial ecosystem is","images":[],"options":{"A":"geothermal energy","B":"hydroelectric power","C":"solar energy","D":"nuclear power"},"answer":"C","explanation":"Solar energy is the source of energy for most Ecosystem. The solar Energy (Sun) gives off more energy than we need to power everything on Earth.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>35","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"By how much is the export of Japan higher than that of Ghana in 2009?","images":["data:image/png;base64,"],"options":{"A":"1,500 million","B":"2,200 million","C":"2,800 million","D":"3,300 million"},"answer":"A","explanation":"The expert of Japan in 2009 which is denoted by   is 2000 million dollars which export for Ghana is 500 million dollars which their difference give Japan - Ghana = 1,500 million dollars.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>36","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"How much did the United state of America (U.S.A) spent on import in 2009?","images":["data:image/png;base64,"],"options":{"A":"3,000 million","B":"2,200 million","C":"2,800 million","D":"1,000 million"},"answer":"D","explanation":"United State of America (U.S.A) spent 1000 million dollar on import in 2009.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>37","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The statistical method used for representing the data above is","images":["data:image/png;base64,"],"options":{"A":"pie chart","B":"divided bar graph","C":"histogram","D":"line graph"},"answer":"B","explanation":"The statistical method used for representing the data is divided bar graph which each segment of the bar graph contains two zone (import and export zone)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>38","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The problems associated with the world's high population growth rate include all the following except","images":[],"options":{"A":"housing problem","B":"inadequate food","C":"pressure on social amenities","D":"adequate medical facilities"},"answer":"D","explanation":"The problems associated with the world's high population growth rate include housing problems, inadequate food, and pressure on social amenities. However, adequate medical facilities are not a problem associated with high population growth rate. In fact, in areas with high population growth rates, there is often a lack of adequate medical facilities, not an abundance.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>39","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following is the smallest form of settlement?","images":[],"options":{"A":"Farmstead","B":"Village","C":"Mitropolis","D":"Town"},"answer":"A","explanation":"The smallest form of settlement is a farmstead. A farmstead is a single farm or a collection of farms, typically consisting of a farmhouse and various outbuildings. It is smaller than a village, town, or metropolis, which are all larger forms of human settlements.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>40","subject":"Geography","year":"2014","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following best explains why limestone areas are often dry?","images":[],"options":{"A":"Limestone areas are subject to excessive evaporation","B":"There is little rainfall in limestone areas","C":"Rain water percolates easily through limestone rocks","D":"Limestone areas have a lot of springs"},"answer":"C","explanation":"Limestone areas are often dry due to the ability of limestone to allowing rain water pass on percolates easily through it.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>41","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"An advantage of air transport in the world is its","images":[],"options":{"A":"high patronage","B":"ability to carry bulky goods","C":"affordability to the masses","D":"speedy movement of goods and passengers."},"answer":"D","explanation":"Air transport unlike the other forms of transport medium has a low distribution rate which gives it a speedy movement of goods and passengers.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>42","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Leather works, carving cloth weaving are examples of","images":[],"options":{"A":"chemical industry","B":"factory industry","C":"local craft industry","D":"heavy industry"},"answer":"C","explanation":"Leather works, carving, and cloth weaving are examples of local craft industries. These are typically small-scale, traditional, and often manual forms of manufacturing, as opposed to larger scale, mechanized factory or heavy industries.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>43","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following metals is used extensively in the electrical industry?","images":[],"options":{"A":"Magnesium","B":"Carbon","C":"Copper","D":"Aluminium"},"answer":"C","explanation":"Copper as a metal is extensively in the electrical industry due to its higher ductility and conductivity of electricity.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>44","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"A port that specializes in receiving and redistributing goods to other nations is","images":[],"options":{"A":"a river port","B":"an airport","C":"an entreport","D":"an inland port"},"answer":"C","explanation":"An entreport is a port that specializes in receiving and redistributing goods to other nations. It is a commercial center where goods are received for distribution, transshipment, or re-exporting. Unlike a river port, an airport, or an inland port, an entreport is specifically designed for the transshipment of goods without them entering into the customs territory.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2014>45","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The concentration of industries in urban centres of developing countries is due to all the following except","images":[],"options":{"A":"high demand","B":"availability of labour","C":"location of raw materials","D":"presence of infrastructural facilities"},"answer":"C","explanation":"Location of raw materials is not one of the reasons of the concentration of industries in Urban centres of the developing countries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>46","subject":"Geography","year":"2014","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Which objective of the Economic Community of West African States (ECOWAS) is performed by WFU?","images":[],"options":{"A":"language integration","B":"Common currency","C":"Free movement","D":"Cultural integration"},"answer":"C","explanation":"The West African Farmers Union (WFU) is an organization that promotes the free movement of agricultural goods and services across West Africa. This is in line with the Economic Community of West African States (ECOWAS) objective of promoting free movement of goods, services, and people across member states.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>47","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The export trade of most West Africa countries consists of","images":[],"options":{"A":"machineries","B":"primary products","C":"processed goods","D":"dairy products"},"answer":"B","explanation":"The export trade of most West African countries consists of primary products. These are raw materials or agricultural products that have not been processed or manufactured. This is due to the fact that many West African countries have economies that are heavily dependent on agriculture and the extraction of natural resources.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>48","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The measure of population concentration in a place is called","images":[],"options":{"A":"population pyramid","B":"population density","C":"emigration","D":"net migration"},"answer":"B","explanation":"Population density is the measure of population concentration in a place or community and it can also be defined as the no of population of individual in a place divided by the total no of population which can be accommodated in the place.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2014>49","subject":"Geography","year":"2014","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following factors can be used to differentiate between a village and a town?","images":[],"options":{"A":"Location","B":"Structure","C":"Pattern","D":"Function"},"answer":"D","explanation":"The function of a place can be used to differentiate between a village and a town. A village is typically a residential area where people live, often in a rural setting. A town, on the other hand, has more commercial and administrative functions, with businesses, schools, and government offices.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2014>50","subject":"Geography","year":"2014","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"The financial headquarters of the Economic Community of West African States (ECOWAS) is located at","images":[],"options":{"A":"Lome","B":"Banjul","C":"Lagos","D":"Cotonou"},"answer":"A","explanation":"The financial head-quarters of the Economic Community of West African States (ECOWAS) is located at lome.","marks":"1","difficulty":"3"}];